%% Make polar scatter plots showing phase locking data across age/genotype groups 
%See R files for final plotting code
running_states = {'allrun' 'runthresh' 'nonrun' 'all'};
regions = {'M2' 'M3' 'M1'};  
groups = {'6wt' '63x' '8wt' '83x'};
celltypes = {'inhibitory' 'excitatory'  }; %'inhibitory' 'excitatory'
fig_idx1 = 10;
fig_idx2 = 20;
fig_idx3 = 30;

for reg = 1:length(regions)
    region = regions{reg};
    
    if strcmp(region, 'M2') %find indices for current layer
        cells_in_layer = M2;
    elseif strcmp(region, 'M3')
        cells_in_layer = M3;
    elseif strcmp(region, 'M1')
        cells_in_layer = M1;
    end 
    
    for t = 1:length(celltypes)
        celltype = celltypes{t};
        fig_idx1 = fig_idx1 + 1;
        fig_idx2 = fig_idx2 + 1;
        fig_idx3 = fig_idx3 + 1;

        if strcmp(celltype, 'excitatory')
            cells_in_type = intersect(exc, cells_in_layer);
        elseif strcmp(celltype, 'inhibitory')
            cells_in_type = intersect(inh, cells_in_layer);
        end
                
        for rs=1:length(running_states)
        running_state = running_states{rs};
        
 
            for g=1:length(groups)
                group = groups{g};

                cells_in_group = find(contains(group_ind, group));

                cells = intersect(cells_in_type, cells_in_group);
 
                if strcmp(running_state, 'allrun')
                    r2CA1theta = r2CA1theta_all_run(cells);
                    r2MECtheta = r2MECtheta_all_run(cells);
                    mu2CA1theta = mu2CA1theta_all_run(cells);
                    mu2MECtheta = mu2MECtheta_all_run(cells);
                    mFR_state = mFR_all_run(cells);
                    c_state = c(cells);

                elseif strcmp(running_state, 'runthresh')
                    r2CA1theta = r2CA1theta_run_thresh(cells);
                    r2MECtheta = r2MECtheta_run_thresh(cells);
                    mu2CA1theta = mu2CA1theta_run_thresh(cells);
                    mu2MECtheta = mu2MECtheta_run_thresh(cells);
                    mFR_state = mFR_run_thresh(cells);
                    c_state = c(cells);


                 elseif strcmp(running_state, 'nonrun')
                    r2CA1theta = r2CA1theta_non_run(cells);
                    r2MECtheta = r2MECtheta_non_run(cells);
                    mu2CA1theta = mu2CA1theta_non_run(cells);
                    mu2MECtheta = mu2MECtheta_non_run(cells);
                    mFR_state = mFR_non_run(cells);
                    c_state = c(cells);


                 elseif strcmp(running_state, 'all')
                    r2CA1theta = r2CA1theta_all(cells);
                    r2MECtheta = r2MECtheta_all(cells);
                    mu2CA1theta = mu2CA1theta_all(cells);
                    mu2MECtheta = mu2MECtheta_all(cells);
                    mFR_state = mFR_all(cells);
                    c_state = c(cells);

                end 

                
                figure(fig_idx1); subplot(1,4,rs); 
                title([region ' ' celltype ' PL to MEC ' running_state]);
                if strcmp(group, '6wt')
                    polarscatter(mu2MECtheta+pi,r2MECtheta,10,[0.3010 0.7450 0.9330], 'filled', 'MarkerFaceAlpha',.5) 
                    hold on;
                elseif strcmp(group, '8wt')
                    polarscatter(mu2MECtheta+pi,r2MECtheta,10,[0.3 0.3 0.8], 'filled', 'MarkerFaceAlpha',.5) 
                elseif strcmp(group, '63x')
                    polarscatter(mu2MECtheta+pi,r2MECtheta,10,[0.8 0.5 0.6], 'filled', 'MarkerFaceAlpha',.5) 
                elseif strcmp(group, '83x')
                    polarscatter(mu2MECtheta+pi,r2MECtheta,10,[0.4940 0.1840 0.5560], 'filled', 'MarkerFaceAlpha',.5) 
                end
           
                figure(fig_idx2); subplot(1,4,rs);
                title([region ' ' celltype ' PL to CA1 ' running_state]);
                if strcmp(group, '6wt')
                    polarscatter(mu2CA1theta+pi,r2CA1theta,10,[0.3010 0.7450 0.9330], 'filled', 'MarkerFaceAlpha',.5) 
                    hold on;
                elseif strcmp(group, '8wt')
                    polarscatter(mu2CA1theta+pi,r2CA1theta,10,[0.3 0.3 0.8], 'filled', 'MarkerFaceAlpha',.5) 
                elseif strcmp(group, '63x')
                    polarscatter(mu2CA1theta+pi,r2CA1theta,10,[0.8 0.5 0.6], 'filled', 'MarkerFaceAlpha',.5) 
                elseif strcmp(group, '83x')
                    polarscatter(mu2CA1theta+pi,r2CA1theta,10,[0.4940 0.1840 0.5560], 'filled', 'MarkerFaceAlpha',.5) 
                end

                if strcmp(running_state, 'allrun')
                figure(fig_idx3);
                xlabel('Firing Rate')
                ylabel('r2MECtheta')
                zlabel('mu2MECtheta')
                title([region ' ' celltype ' ' running_state ' FR and PL to MEC']);
                if strcmp(group, '6wt')
                    scatter3(mFR_state,r2MECtheta,mu2MECtheta,20, [0.3010 0.7450 0.9330]);
                    hold on;
                elseif strcmp(group, '8wt')
                     scatter3(mFR_state,r2MECtheta,mu2MECtheta,20, [0.3 0.3 0.8]);
                elseif strcmp(group, '63x')
                     scatter3(mFR_state,r2MECtheta,mu2MECtheta,20, [0.8 0.5 0.6]);
                elseif strcmp(group, '83x')
                     scatter3(mFR_state,r2MECtheta,mu2MECtheta,20, [0.4940 0.1840 0.5560]);
                end
                end


            end
            
        end     

    end

end


