Animalname = animal_ind;
Groupname = group_ind;
Sex = sex_ind;
Age_real = age_ind;
Shank = shank_ind;


for i = 1:length(animal_ind)
    if ismember(i, MEC3)
        mec_reg = 'MEC3';
    elseif ismember(i, MEC2)
        mec_reg = 'MEC2';
    elseif ismember(i, MEC1)
        mec_reg = 'MEC1';
    else 
        mec_reg = 'other';
    end
    
    if ismember(i, exc)
        type = 'e';
    elseif ismember(i, inh)
        type = 'i';
    else
        type = 'w';
    end    
    
    Region{i} = mec_reg;
    CellType{i} = type;
    
end 

